import "../quiz_question.dart";

const _subject = "Arabic";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// JAMB Arabic — 100 questions covering the five core UTME sections:
/// Comprehension (المطالعة), Translation (الترجمة), Grammar and Structure
/// (النحو والصرف), Composition (الإنشاء), and Arabic Literature (الأدب
/// العربي). Weighted toward well-established grammar concepts and
/// author-level literary-history facts rather than fine-grained
/// classical text analysis.
List<QuizQuestion> buildJambArabicQuestions() {
  return [
    ..._comprehension,
    ..._translation,
    ..._grammarAndStructure,
    ..._composition,
    ..._arabicLiterature,
  ];
}

